// Normalizar estructura de clases desde Excel
const items = $input.all();
const carrera = $('Loop Over Items').item.json.carrera;
const clasesNormalizadas = [];

for (const item of items) {
  const row = item.json;

  // Skip headers y rows vacías
  if (!row || Object.values(row).every(v => !v || v === '')) continue;

  // Extrae campos (ajusta según tus columnas)
  const materia = row['ASIGNATURA'] || row['MATERIA'] || row['Nombre Curso'] || row['Materia'] || '';
  const ciclo = row['CICLO'] || row['NIVEL'] || row['Sección'] || row['Ciclo'] || '';
  const dia = row['DÍA'] || row['DIA'] || row['Día'] || row['Dia'] || '';
  const horario = row['HORA'] || row['HORARIO'] || row['Horario'] || '';
  const numEst = parseInt(row['NRO. ESTUDIANTES'] || row['# ESTUDIANTES'] || row['Cupos'] || row['Estudiantes'] || 0);
  const aula = row['AULA'] || row['AULA/LAB'] || row['Aula'] || '';
  const docente = row['DOCENTE'] || row['Docente'] || '';
  const paralelo = row['PARALELO'] || row['Paralelo'] || '';
  const modalidad = row['MODALIDAD'] || row['Modalidad'] || 'PRESENCIAL';

  if (!materia || !dia || !horario) continue;

  // Parsea horario (ej: "14:00 - 17:00" o "14:00-17:00")
  const horaMatch = horario.match(/(\d{1,2}):(\d{2})\s*-\s*(\d{1,2}):(\d{2})/);
  let horaInicio, horaFin;

  if (horaMatch) {
    horaInicio = `${horaMatch[1].padStart(2, '0')}:${horaMatch[2]}:00`;
    horaFin = `${horaMatch[3].padStart(2, '0')}:${horaMatch[4]}:00`;
  } else {
    continue; // Skip si no puede parsear
  }

  clasesNormalizadas.push({
    carrera: carrera,
    materia: materia.trim(),
    ciclo: String(ciclo).trim(),
    paralelo: String(paralelo).trim(),
    dia: dia.trim().toUpperCase(),
    hora_inicio: horaInicio,
    hora_fin: horaFin,
    num_estudiantes: numEst,
    docente: docente.trim(),
    aula_sugerida: aula.trim(),
    modalidad: modalidad.trim().toUpperCase()
  });
}

return clasesNormalizadas.map(c => ({ json: c }));

