// Algoritmo de asignación de aulas
const clases = $('Postgres - Insertar Clases').all().map(item => item.json);
const aulas = $input.all().map(item => item.json);

// Mapa de ocupación: {aula_id: {dia: [horarios ocupados]}}
const ocupacion = {};
aulas.forEach(aula => {
  ocupacion[aula.id] = {};
});

// Helper: Verifica si hay conflicto de horario
function hayConflicto(aulaId, dia, horaInicio, horaFin) {
  if (!ocupacion[aulaId][dia]) return false;

  for (const horario of ocupacion[aulaId][dia]) {
    // Conflicto si se superponen
    if (horaInicio < horario.fin && horaFin > horario.inicio) {
      return true;
    }
  }
  return false;
}

// Helper: Marca horario como ocupado
function marcarOcupado(aulaId, dia, horaInicio, horaFin) {
  if (!ocupacion[aulaId][dia]) {
    ocupacion[aulaId][dia] = [];
  }
  ocupacion[aulaId][dia].push({ inicio: horaInicio, fin: horaFin });
}

// Helper: Calcula score de prioridad
function calcularPrioridad(clase, aula) {
  let score = 0;

  // +100 si el aula tiene prioridad para esta carrera
  if (aula.prioridad_carreras && aula.prioridad_carreras.includes(clase.carrera)) {
    score += 100;
  }

  // +50 si es la misma aula sugerida
  if (clase.aula_sugerida && aula.nombre === clase.aula_sugerida) {
    score += 50;
  }

  // +20 si la capacidad es ajustada (no muy grande, no muy pequeña)
  const margen = aula.capacidad - clase.num_estudiantes;
  if (margen >= 0 && margen <= 10) {
    score += 20;
  } else if (margen > 10) {
    score += 10; // Penaliza aulas demasiado grandes
  }

  // +30 si requiere lab y es lab
  if (clase.aula_sugerida && clase.aula_sugerida.toLowerCase().includes('lab') && aula.es_laboratorio) {
    score += 30;
  }

  return score;
}

// Ordena clases por prioridad
clases.sort((a, b) => {
  const prioridadA = aulas.some(aula => aula.prioridad_carreras && aula.prioridad_carreras.includes(a.carrera)) ? 1 : 0;
  const prioridadB = aulas.some(aula => aula.prioridad_carreras && aula.prioridad_carreras.includes(b.carrera)) ? 1 : 0;

  if (prioridadA !== prioridadB) return prioridadB - prioridadA;

  // Luego por número de estudiantes (más grande primero)
  return b.num_estudiantes - a.num_estudiantes;
});

// Asignación
const asignaciones = [];
const sinAsignar = [];

for (const clase of clases) {
  let mejorAula = null;
  let mejorScore = -1;

  for (const aula of aulas) {
    // Verifica capacidad
    if (aula.capacidad < clase.num_estudiantes) continue;

    // Verifica conflictos
    if (hayConflicto(aula.id, clase.dia, clase.hora_inicio, clase.hora_fin)) continue;

    // Calcula score
    const score = calcularPrioridad(clase, aula);

    if (score > mejorScore) {
      mejorScore = score;
      mejorAula = aula;
    }
  }

  if (mejorAula) {
    asignaciones.push({
      clase_id: clase.id || null,
      aula_id: mejorAula.id,
      aula_nombre: mejorAula.nombre,
      carrera: clase.carrera,
      materia: clase.materia,
      dia: clase.dia,
      hora_inicio: clase.hora_inicio,
      hora_fin: clase.hora_fin,
      num_estudiantes: clase.num_estudiantes,
      capacidad_aula: mejorAula.capacidad
    });

    marcarOcupado(mejorAula.id, clase.dia, clase.hora_inicio, clase.hora_fin);
  } else {
    sinAsignar.push(clase);
  }
}

// Retorna asignaciones y estadísticas
return [{
  json: {
    asignaciones: asignaciones,
    total_asignadas: asignaciones.length,
    sin_asignar: sinAsignar.length,
    conflictos: sinAsignar
  }
}];
